// Step 1: Define Type
type StatusType string

// Step 2: Define Enum Values
const (
	StatusPending   StatusType = "pending"
	StatusApproved  StatusType = "approved"
	StatusRejected  StatusType = "rejected"
	StatusCancelled StatusType = "cancelled"
)

// Step 3: MarshalJSON (Go → JSON)
func (s StatusType) MarshalJSON() ([]byte, error) {
	return json.Marshal(string(s))
}

// Step 4: UnmarshalJSON (JSON → Go)
func (s *StatusType) UnmarshalJSON(b []byte) error {

	var input string
	if err := json.Unmarshal(b, &input); err != nil {
		return err
	}

	input = strings.TrimSpace(strings.ToLower(input))

	switch input {

	// Pending
	case "pending", "p", "1":
		*s = StatusPending

	// Approved
	case "approved", "approve", "a", "2":
		*s = StatusApproved

	// Rejected
	case "rejected", "reject", "r", "3":
		*s = StatusRejected

	// Cancelled
	case "cancelled", "cancel", "c", "4":
		*s = StatusCancelled

	default:
		return errors.New("invalid status_type")
	}

	return nil
}

func (s StatusType) MarshalJSON() ([]byte, error) {
	return json.Marshal(string(s))
}

