package middlewares

import (
	"crypto/subtle"
	"net/http"
	"strings"
	"visual_search_backend_go/config"
	"github.com/gin-gonic/gin"
)

func TokenMiddleware() gin.HandlerFunc {
	return func(ginCtx *gin.Context) {
		const authPrefix = "Bearer "
		authHeader := ginCtx.GetHeader("Authorization")

		if authHeader == "" {
			ginCtx.JSON(http.StatusUnauthorized, gin.H{"error": "missing token"})
			// >>> যদি token invalid হয়: response পাঠিয়ে দাও -> আর controller এ যেও না
			ginCtx.Abort()
			return
		}

		if !strings.HasPrefix(authHeader, authPrefix) {
			ginCtx.JSON(http.StatusUnauthorized, gin.H{"error": "invalid format"})
			// >>> যদি token invalid হয়: response পাঠিয়ে দাও -> আর controller এ যেও না
			ginCtx.Abort()
			return
		}

		tokenString := strings.TrimPrefix(authHeader, authPrefix)

		// Step 1: FullPath
		path := ginCtx.FullPath()

		// Step 2: API prefix remove
		path = strings.TrimPrefix(path, config.APIPrefix)

		// Step 3: empty fallback
		if path == "" {
			path = "/"
		}

		expectedTokens := map[string]string{
			"/product1": config.ProductToken1,
			"/product2": config.ProductToken2,
		}

		expectedToken, exists := expectedTokens[path]

		if !exists {
			ginCtx.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "unauthorized"})
			return
		}

		// >> ENV token missing check
		if expectedToken == "" {
			ginCtx.AbortWithStatusJSON(http.StatusInternalServerError, gin.H{"error": "server config error"})
			return
		}

		// >>> Timing attack fix
		if subtle.ConstantTimeCompare([]byte(expectedToken), []byte(tokenString)) != 1 {
			ginCtx.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}

		ginCtx.Next()

	}
}

func SetRoutes(route *gin.Engine) {

	api := route.Group(config.APIPrefix) // >>> Common Prefix Set
	api.Use(middlewares.TokenMiddleware())// >>> Call Middlewares For Token
	api.POST("/product1", controllers.UploadProducts)
	api.POST("/product2", controllers.UploadOrders)

}

