/// >>> Grid Line Create =======================================================
class GridPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final paint = Paint()
      ..color = Colors.white.withValues(alpha: 0.05)
      ..strokeWidth = 1;
    const double spacing = 40;
    // >>> Vertical lines
    for (double x = 0; x < size.width; x += spacing) {
      canvas.drawLine(Offset(x, 0), Offset(x, size.height), paint);
    }

    // >>>  Horizontal lines
    for (double y = 0; y < size.height; y += spacing) {
      canvas.drawLine(Offset(0, y), Offset(size.width, y), paint);
    }
  }
  @override
  bool shouldRepaint(CustomPainter oldDelegate) => false;
}
/// <<< Grid Line Create =======================================================

/// >>> Wavy Line two variant ==================================================
class DarkWavePainter extends CustomPainter {
  final double heightFactor;
  final double opacity;
  final int variant;

  DarkWavePainter({required this.heightFactor, required this.opacity, required this.variant,});

  @override
  void paint(Canvas canvas, Size size) {
    final path = Path();

    //  Start point
    path.moveTo(0, size.height * heightFactor);

    //  Smooth wave system (improved bezier curves)
    final double h = size.height * heightFactor;

    if (variant == 1) {
      path.cubicTo(
        size.width * 0.25, h - 40,
        size.width * 0.45, h + 60,
        size.width, h - 0,
      );

      path.cubicTo(
        size.width * 0.85, h + 30,
        size.width, h - 10,
        size.width, h,
      );
    }

    else if (variant == 2) {
      path.moveTo(0, h);

      path.cubicTo(
        size.width * 0.10, h + 18,
        size.width * 0.20, h + 18,
        size.width * 0.30, h,
      );

      path.cubicTo(
        size.width * 0.40, h - 18,
        size.width * 0.50, h - 18,
        size.width * 0.60, h,
      );

      path.cubicTo(
        size.width * 0.70, h + 18,
        size.width * 0.80, h + 18,
        size.width * 0.90, h,
      );

      path.cubicTo(
        size.width * 0.97, h - 14,
        size.width, h - 6,
        size.width, h,
      );
    }

    //  Close shape smoothly
    path.lineTo(size.width, size.height);
    path.lineTo(0, size.height);
    path.close();

    final paint = Paint()
      ..shader = LinearGradient(
        colors: [
          Colors.white.withOpacity(opacity),
          Colors.transparent,
        ],
        begin: Alignment.topCenter,
        end: Alignment.bottomCenter,
      ).createShader(Rect.fromLTWH(0, 0, size.width, size.height));

    canvas.drawPath(path, paint);
  }

  @override
  bool shouldRepaint(covariant CustomPainter oldDelegate) => true;
}
